// Topic shape: system-sensors/sensor/<id>/state
// <id> is either "netalertx" (aggregate scan stats) or "mac_xx_xx_xx_xx_xx_xx" (per-device attrs).
// CARD-0078: this used to also detect new devices by diffing each mac_* payload's
// is_new flag against a Node-RED flow-context cache — removed because that cache is
// memory-only and resets on every Node-RED restart, causing false re-alerts for any
// device NetAlertX still considers "new" (i.e. never acknowledged/named in its UI).
// New-device alerting now comes from NetAlertX's own Notifications webhook instead —
// see the webhook flow below, which uses NetAlertX's persistent, correctly-deduped
// server-side computation rather than re-deriving it here.
const parts = msg.topic.split('/');
const id = parts.length >= 3 ? parts[2] : '';

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.warn('Bad JSON on ' + msg.topic);
        return null;
    }
}

if (id === 'netalertx') {
    // Aggregate scan stats — cache for the heartbeat, no transition to log here.
    // flow-scoped: fn_heartbeat is a different node and needs to read this back.
    flow.set('agg_stats', payload);
}

return null;

// HMAC verification (CARD-0078) — NetAlertX signs its webhook body with WEBHOOK_SECRET,
// header X-Webhook-Signature: sha256=<hex>. crypto is injected via this node's libs config
// (Node-RED 4.x Function nodes disallow bare require() calls).
//
// Raw bytes: this Node-RED version has no msg.req.rawBody — the http in node's
// "skipBodyParsing" property must be enabled instead, which delivers the untouched
// request body as msg.payload (a Buffer) rather than a pre-parsed JSON object.
// Confirmed via /usr/lib/node_modules/node-red/node_modules/@node-red/nodes/core/network/21-httpin.js
// on the Pi (rawBodyCapture middleware, gated on the node's skipBodyParsing flag).
//
// CONFIRMED UPSTREAM BUG (NetAlertX v26.7.1, _publisher_webhook/webhook.py): the plugin
// signs json.dumps(_json_payload, separators=(',', ':')) (compact, no spaces) but actually
// transmits json.dumps(_json_payload) — Python's DEFAULT separators, which include spaces
// after ':' and ','. These are different byte sequences for the same data, so verifying
// against the raw received bytes will NEVER match NetAlertX's own signature. Proved this
// directly: captured a real rejected request, parsed it, re-serialized with Python's
// compact+ensure_ascii rules, and that reproduced NetAlertX's sent signature exactly.
//
// Workaround: parse the received body, then re-serialize it ourselves matching Python's
// json.dumps(obj, separators=(',', ':')) behavior (compact, ensure_ascii=True — non-ASCII
// chars, including emoji as UTF-16 surrogate pairs, escaped as \uXXXX) via pyJsonDumps()
// below, and verify the signature against THAT reconstruction instead of the raw bytes.
// This only works because JSON.parse is side-effect-free on unverified input — nothing
// from the parsed body is acted on (no log message composed) until AFTER the signature
// check passes below.
//
// IMPORTANT: the http response node needs msg.req/msg.res to know which connection to
// reply to — those only survive if we mutate the original msg object, not construct new
// object literals for the response output.

function pyJsonDumps(obj) {
    if (obj === null || obj === undefined) return 'null';
    if (obj === true) return 'true';
    if (obj === false) return 'false';
    if (typeof obj === 'number') return String(obj);
    if (typeof obj === 'string') {
        var out = '"';
        for (var i = 0; i < obj.length; i++) {
            var ch = obj[i];
            var code = obj.charCodeAt(i);
            if (ch === '"') out += '\\"';
            else if (ch === '\\') out += '\\\\';
            else if (code === 0x08) out += '\\b';
            else if (code === 0x0c) out += '\\f';
            else if (code === 0x0a) out += '\\n';
            else if (code === 0x0d) out += '\\r';
            else if (code === 0x09) out += '\\t';
            else if (code < 0x20 || code > 0x7e) out += '\\u' + code.toString(16).padStart(4, '0');
            else out += ch;
        }
        return out + '"';
    }
    if (Array.isArray(obj)) {
        return '[' + obj.map(pyJsonDumps).join(',') + ']';
    }
    if (typeof obj === 'object') {
        var parts = Object.keys(obj).map(function (k) {
            return pyJsonDumps(k) + ':' + pyJsonDumps(obj[k]);
        });
        return '{' + parts.join(',') + '}';
    }
    return 'null';
}

const secret = env.get('NETALERTX_WEBHOOK_SECRET');
const sigHeader = msg.req && msg.req.headers && msg.req.headers['x-webhook-signature'];
const raw = Buffer.isBuffer(msg.payload) ? msg.payload : null;

if (!secret) {
    node.error('NETALERTX_WEBHOOK_SECRET not set in Node-RED environment');
    msg.statusCode = 500;
    msg.payload = 'server misconfigured';
    return [msg, null];
}

if (!sigHeader || !raw) {
    node.warn('NetAlertX webhook: rejected — sigHeader present: ' + (!!sigHeader) + ', rawBody present: ' + (!!raw));
    msg.statusCode = 401;
    msg.payload = 'unauthorized';
    return [msg, null];
}

let body;
try {
    body = JSON.parse(raw.toString('utf8'));
} catch (e) {
    node.warn('Bad JSON from NetAlertX webhook');
    msg.statusCode = 400;
    msg.payload = 'bad json';
    return [msg, null];
}

// Reconstruct the exact string NetAlertX actually signed (its own compact-serialization
// bug, worked around here — see notes above).
const compactForm = pyJsonDumps(body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(compactForm, 'utf8').digest('hex');
let valid = false;
try {
    valid = crypto.timingSafeEqual(Buffer.from(sigHeader), Buffer.from(expected));
} catch (e) {
    valid = false; // length mismatch, malformed header, etc.
}

if (!valid) {
    node.warn('NetAlertX webhook: signature mismatch (even after compact-reserialization workaround) — received: ' + sigHeader + ' | expected: ' + expected);
    msg.statusCode = 401;
    msg.payload = 'unauthorized';
    return [msg, null];
}

// Verified. NetAlertX's webhook publisher always wraps its payload Slack/Discord-style.
// body.attachments[0].text holds the real notification content — but as a DOUBLE-ENCODED
// JSON STRING, not a nested object: NetAlertX's Notifications table stores its JSON column
// as text, and that text gets embedded as-is (then string-escaped by the outer json.dumps),
// not parsed back into an object first. Confirmed directly against a real payload — needs
// a second JSON.parse.
let data = body && body.attachments && body.attachments[0] && body.attachments[0].text;
if (typeof data === 'string') {
    try {
        data = JSON.parse(data);
    } catch (e) {
        node.warn('NetAlertX webhook: could not parse nested notification JSON');
        data = {};
    }
}
data = data || {};
const newDevices = Array.isArray(data.new_devices) ? data.new_devices : [];

// Event-time convention (CLAUDE.md): this relay posts well after the device actually
// connected, so the message must carry NetAlertX's own eveDateTime, not just rely on
// the log server's receipt timestamp — this bug is exactly what that convention exists
// to prevent.
const logMsgs = newDevices.map(function (d) {
    const label = d.devVendor || d.devName || 'unknown device';
    let when = 'unknown time';
    if (d.eveDateTime) {
        try {
            when = new Date(d.eveDateTime).toLocaleString('en-US', {
                timeZone: 'America/Phoenix', hour12: false
            }) + ' MST';
        } catch (e) { when = d.eveDateTime; }
    }
    return {
        payload: JSON.stringify({
            component: 'netalertx',
            category: 'Alert',
            message: 'New device detected: ' + label + ' (' + d.eveMac + ', ' +
                (d.eveIp || 'no IP') + ') — connected ' + when
        })
    };
});

msg.statusCode = 200;
msg.payload = 'OK';
return [msg, logMsgs.length ? logMsgs : null];

const stats = flow.get('agg_stats');
let statsText = 'no scan data yet';
if (stats) {
    statsText = stats.online + ' online, ' + stats.down + ' down, ' + stats.all + ' total' +
        (stats.new > 0 ? ', ' + stats.new + ' new' : '') +
        (stats.unknown > 0 ? ', ' + stats.unknown + ' unknown' : '');
}

const logMsg = {
    payload: JSON.stringify({
        component: 'netalertx',
        category: 'System',
        message: 'Heartbeat - ' + statsText
    })
};

const heartbeatMsg = {
    payload: JSON.stringify({
        component: 'netalertx',
        stats: stats || {}
    })
};

return [logMsg, heartbeatMsg];
